// src/App.js
import React from "react";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import AppRoutes from "./routes/AppRoutes";

// Auth Pages
import Login from "./pages/auth/Login";
import Register from "./pages/auth/Register";

const NotFound = () => (
  <div
    style={{
      display: "flex",
      flexDirection: "column",
      justifyContent: "center",
      alignItems: "center",
      height: "80vh",
      textAlign: "center",
      padding: "20px",
      color: "#374151",
      fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
    }}
  >
    <h1
      style={{
        fontSize: "2.5rem",
        color: "#ef4444",
        marginBottom: "15px",
        fontWeight: "700",
      }}
    >
      404 Not Found
    </h1>
    <p style={{ fontSize: "1.1rem", maxWidth: "400px", marginBottom: "20px" }}>
      The page you are looking for does not exist or has been moved.
    </p>
    <a
      href="/"
      style={{
        color: "#a71010",
        fontWeight: "600",
        textDecoration: "underline",
        cursor: "pointer",
        transition: "color 0.3s ease",
      }}
      onMouseOver={e => (e.currentTarget.style.color = "#7a0c0c")}
      onMouseOut={e => (e.currentTarget.style.color = "#a71010")}
    >
      Return to Home
    </a>
  </div>
);

function App() {
  const userRole = localStorage.getItem("role");

  return (
    <Router>
      <Routes>
        {/* Root route: redirect logged-in users to their dashboard, otherwise show Login */}
        <Route
          path="/"
          element={userRole ? <Navigate to={`/${userRole}`} replace /> : <Login />}
        />

        {/* Registration page */}
        <Route path="/register" element={<Register />} />

        {/* Nested dashboard and protected routes */}
        <Route path="/*" element={<AppRoutes />} />

        {/* Catch-all fallback 404 */}
        <Route path="*" element={<NotFound />} />
      </Routes>
    </Router>
  );
}

export default App;
